SELECT
id,
parameter_id    AS parameterId,  count,
resolution,
unit,
created_at      AS createdAt,
updated_at      AS updatedAt
FROM time_axis


        AND id = #{id}



        AND parameter_id = #{parameterId}



        AND count = #{count}



        AND resolution = #{resolution}



        AND unit = #{unit}



ORDER BY created_at DESC
